export const STRUCTURAL_ZH_TEMPLATES = Object.freeze(TEMPLATE_ROWS.map((row) => Object.freeze({ ...row, pattern: new RegExp(row.pattern, "u") })));

export function canonicalizeStructuralValue(value = "") {
  return STRUCTURAL_EN_CANONICAL_BY_ZH[value] ?? value;
}

function localizeAtomicCapture(value = "", locale = "en") {
  const canonical = canonicalizeStructuralValue(value);
  if (locale === "en") return canonical;
  return STRUCTURAL_ZH_EXACT[canonical] ?? canonical;
}

export function localizeStructuralCapture(value = "", locale = "en") {
  const canonical = canonicalizeStructuralValue(value);
  if (locale === "en") return canonical;
  const exact = STRUCTURAL_ZH_EXACT[canonical];
  if (exact !== undefined) return exact;
  const fieldAtRow = canonical.match(/^(.+?) at row (\d+)$/u);
  if (fieldAtRow) return `第 ${fieldAtRow[2]} 行的 ${localizeAtomicCapture(fieldAtRow[1], "zh")}`;
  if (canonical.includes(", ")) {
    return canonical.split(", ").map((part) => localizeAtomicCapture(part, "zh")).join("、");
  }
  return canonical;
}

export function localizeStructuralValue(value = "", locale = "en") {
  const canonical = canonicalizeStructuralValue(value);
  if (locale === "en") return canonical;
  const exact = STRUCTURAL_ZH_EXACT[canonical];
  if (exact !== undefined) return exact;
  for (const template of STRUCTURAL_ZH_TEMPLATES) {
    const match = template.pattern.exec(canonical);
    if (!match) continue;
    const captures = match.slice(1);
    return template.zhParts.map((part) => typeof part === "number"
      ? localizeStructuralCapture(captures[part] ?? "", "zh")
      : part).join("");
  }
  return canonical;
}
